import React from 'react';
import Sponsors from './Sponsors';

function getYear() {
  return new Date().getFullYear();
}

const footerText = {
  marginBottom: '0',
  fontSize: '.8rem'
}

function Footer() {
  return (
    <>
    <Sponsors />
    <div className="row justify-content-center footer">
      <div className="col">
        <p style={footerText}>For business and media inquiries:</p>
        <p><a href="mailto:jeff@jbrally.com">jeff@jbrally.com</a></p>
        <p style={footerText}>&copy;&nbsp;Jeff&nbsp;Berlin&nbsp;{getYear()}</p>
      </div>
    </div>
    </>
  )
}

export default Footer;
